class JWTLibrary:
    def __init__(self, app: Flask = None):
        self.app = app
        self.jwt_manager = None
        self.algorithms = {}
        if app is not None:
            self.init_app(app)
    
    def init_app(self, app: Flask):
        self.jwt_manager = JWTManager(app)
        app.extensions['jwt_library'] = self
    
    def register_algorithm(self, algorithm: str, public_key: str = None, secret: str = None):
        """Register a signing algorithm with its key"""
        self.algorithms[algorithm] = {
            'public_key': public_key,
            'secret': secret
        }
    
    def verify_token(self, token: str, algorithm: str = None) -> Optional[Dict[str, Any]]:
        """Verify JWT token with specified algorithm"""
        try:
            if algorithm and algorithm in self.algorithms:
                key = self.algorithms[algorithm]['secret'] or self.algorithms[algorithm]['public_key']
                if not key:
                    raise ValueError(f"No key provided for algorithm {algorithm}")
                
                # Decode without verification first to get header
                header = jwt.get_unverified_header(token)
                if not algorithm:
                    algorithm = header.get('alg', 'HS256')
                
                # Verify with proper key
                payload = jwt.decode(
                    token,
                    key,
                    algorithms=[algorithm],
                    options={"verify_signature": True}
                )
                return payload
                
            # Fallback to automatic algorithm detection
            payload = jwt.decode(
                token,
                None,
                algorithms=['HS256', 'RS256', 'HS384', 'HS512', 'RS384', 'RS512'],
                options={"verify_signature": True}
            )
            return payload
            
        except JWTError as e:
            return None
        except Exception:
            return None
    
    def extract_payload(self, token: str) -> Optional[Dict[str, Any]]:
        """Extract payload from JWT token"""
        return self.verify_token(token)
    
    def validate_token(self, token: str, required_roles: list = None) -> bool:
        """Validate token and optionally check roles"""
        payload = self.verify_token(token)
        if not payload:
            return False
        
        if required_roles:
            user_roles = payload.get('roles', [])
            if not any(role in user_roles for role in required_roles):
                return False
        
        return True

