@app.route('/protected', methods=['GET'])
@jwt_required()
def protected():
    current_user = get_jwt_identity()
    return jsonify(logged_in_as=current_user), 200

@app.route('/verify-token', methods=['POST'])
def verify_token():
    token = request.json.get('token', None)
    if not token:
        return jsonify({'msg': 'Token is required'}), 400
    
    payload = jwt_lib.extract_payload(token)
    if not payload:
        return jsonify({'msg': 'Invalid token'}), 401
    
    return jsonify(payload), 200

@app.route('/validate-token', methods=['POST'])
def validate_token_endpoint():
    token = request.json.get('token', None)
    required_roles = request.json.get('roles', [])
    
    if not token:
        return jsonify({'msg': 'Token is required'}), 400
    
    is_valid = jwt_lib.validate_token(token, required_roles)
    if not is_valid:
        return jsonify({'msg': 'Invalid token or insufficient permissions'}), 401
    
    return jsonify({'valid': True}), 200

